// Apuntamos directamente a order.body
const order = items[0].json.body;
const data = order ? order : items[0].json;

// Extraemos los campos principales
const cliente = data.cliente?.nombre || "Sin nombre";
const telefono = data.cliente?.telefono || "No proporcionado";
const total = data.total || 0;
const idOrden = data.orden_id || "000";

// Mapeamos el tipo de entrega
let tipo = '🥡 Para Recoger en Tienda';
if (data.tipo_entrega === 'delivery') {
    tipo = '🛵 Delivery a Domicilio';
} else if (data.tipo_entrega === 'salon') {
    tipo = '🍽️ Consumo en Salón';
}

// Procesamos el array de platos (AJUSTADO A TU JSON REAL)
const filtradoItems = (data.items || []).filter(item => item !== null);
const listaPlatos = filtradoItems.map(item => {
    // Aquí cambiamos 'nombre' por 'plato' y 'precio' por 'precio_unitario'
    const nombrePlato = item.plato || 'Plato sin nombre';
    const precio = item.precio_unitario || 0;
    const cantidad = item.cantidad || 1;

    return `- ${cantidad}x ${nombrePlato} (S/. ${precio.toFixed(2)})`;
}).join('\n');

const textoPlatos = listaPlatos || "- Sin productos específicos";

// Construimos el mensaje final
const mensaje = `🛍️ *NUEVA COMPRA RECIBIDA! (#${idOrden.split('-')[0]})*
----------------------------------
📍 *Canal:* ${tipo}
👤 *Cliente:* ${cliente}
📞 *Teléfono:* ${telefono}

📦 *Detalle del Pedido:*
${textoPlatos}
----------------------------------
💰 *Monto Total:* S/. ${total.toFixed(2)}

⚡ _Por favor, cambiar el estado a "En Cocina" en el Dashboard._ 🌱`;

// Extracción dinámica del destinatario
const destinatarioFinal = data.restaurante_grupo_whatsapp || data.restaurante_telefono;

return {
    json: {
        number: destinatarioFinal, 
        text: mensaje
    }
};

const output = $json.texto_ia || $json.output || "";
const problemas = [];

// Patrones técnicos reales que debemos bloquear
const fugasReales = [
  /supabase/i, 
  /postgresql/i, 
  /fetch failed/i, 
  /node_modules/i, 
  /ECONNREFUSED/i, 
  /\[object Object\]/i,
  /undefined/i
];

for (const patron of fugasReales) {
  if (patron.test(output)) { 
    problemas.push("🔴 fuga_tecnica"); 
    break; 
  }
}

if (output.trim().length === 0) {
  problemas.push("🔴 respuesta_vacia");
}

const severidad = problemas.some(p => p.includes("🔴")) ? "CRITICO" : "WARNING";

if (problemas.length > 0) {
  return [{ 
    json: { 
      output: "¡Uy, perdona! Me distraje un segundo con mis plantas 🌿 ¿Me podrías repetir eso? Quiero asegurarme de darte el mejor consejo 💛",
      _paso: "fallback",
      _guardia: {
          problemas: problemas,
          severidad: severidad,
          outputOriginal: output.substring(0, 1000),
          timestamp: new Date().toISOString()
        }
    }
  }];
}

return [{ 
  json: { 
    ...$json,
    output: output, 
    _paso: "ok" 
  } 
}];

const guardia = $json._guardia;
if (!guardia) return [];

let mensajeUsuario = "";
try {
  // Intentamos obtener el mensaje original del nodo de entrada de WhatsApp
  const inputData = $('Edit Fields1').first();
  if (inputData && inputData.json) {
    mensajeUsuario = inputData.json.message_content || "";
  }
} catch (e) {}

const errorMsg = Array.isArray(guardia.problemas) ? guardia.problemas.join(", ") : "Error desconocido";

return [{
  json: {
    whatsapp_id: $('Set Preparacion').first().json.Numero_usuario || "Desconocido",
    workflow_name: "Mr. Green – Agente Botánico",
    nodo_fallido: "Guardia de Respuesta",
    error_type: errorMsg,
    severity: guardia.severidad || "WARNING",
    original_output: guardia.outputOriginal ? guardia.outputOriginal.substring(0, 800) : "",
    mensaje_usuario: mensajeUsuario ? mensajeUsuario.substring(0, 800) : "",
    execution_id: $execution.id,
    _guardia: guardia // Mantenemos el objeto para el siguiente nodo si es necesario
  }
}];

const guardia = $json._guardia || {};
const problemas = guardia.problemas || ["Error desconocido"];
const telefono = $json.whatsapp_id || "Desconocido";

const mensaje = `🚨 *ALERTA MR. GREEN* 🚨
━━━━━━━━━━━━━━━━━━━━
❌ *Problemas detectados:*
${problemas.join('
')}

👤 *Cliente:* \`${telefono}\`
🔗 *Ejecución:* \`${$execution.id}\`

🤖 *Intentó decir:*
"${guardia.outputOriginal || "(vacío)"}"
━━━━━━━━━━━━━━━━━━━━`;

return [{ json: { mensaje } }];

const texto = $json.output || "";
const longitud = texto.length;
const BASE_DELAY = 1500;
const MS_POR_CARACTER = 45;
let delayFinal = BASE_DELAY + (longitud * MS_POR_CARACTER);
if (delayFinal > 8000) delayFinal = 8000;
if (delayFinal < 1500) delayFinal = 1500;

return [{
    json: {
        ...$json,
        delay_ms: delayFinal,
        delay_seconds: Math.ceil(delayFinal / 1000)
    }
}];

let fullText = $json.output || "";
const MAX_LENGTH = 450; // Límite seguro para un globo de texto
let part1 = "";
let part2 = "";
let needsSplit = false;

if (fullText.length <= MAX_LENGTH) {
    part1 = fullText;
    needsSplit = false;
} else {
    needsSplit = true;

    // Buscamos el mejor punto de corte (Doble Enter, Enter, Punto o Espacio)
    // Empezamos buscando desde el límite (MAX_LENGTH) hacia atrás
    let splitIndex = fullText.lastIndexOf('\n\n', MAX_LENGTH);

    if (splitIndex === -1 || splitIndex < 150) {
        splitIndex = fullText.lastIndexOf('\n', MAX_LENGTH);
    }

    if (splitIndex === -1 || splitIndex < 150) {
        splitIndex = fullText.lastIndexOf('. ', MAX_LENGTH);
    }

    if (splitIndex === -1 || splitIndex < 150) {
        splitIndex = fullText.lastIndexOf(' ', MAX_LENGTH);
    }

    // Si no encontró ningún punto ideal, corta forzosamente en el límite
    if (splitIndex === -1) splitIndex = MAX_LENGTH;

    part1 = fullText.substring(0, splitIndex).trim();
    part2 = fullText.substring(splitIndex).trim();
}

return [{ 
    json: { 
        part1, 
        part2, 
        needs_split: needsSplit, 
        delay_seconds: $json.delay_seconds || 4 
    } 
}];

const payload = $input.first().json.body;
const restaurante = payload.restaurante;
const platos = payload.platos;

return platos.map(plato => ({
  json: {
    nombre: plato.nombre,
    categoria: plato.categoria_nombre,
    ingredientes: plato.ingredientes,
    telefono: restaurante.telefono,
    precio: plato.precio
  }
}));

