// 1. Recuperamos la información original (antes de que la IA la borrara)
const originales = $items("Separar Platos");

// 2. Unimos el texto bonito de la IA con los datos originales
return $input.all().map((item, index) => {
  const original = originales[index].json;

  return {
    json: {
      // Usamos pageContent para que el Data Loader sepa qué es el texto
      pageContent: `Plato: ${original.nombre}. Categoría: ${original.categoria}. Descripción: ${item.json.message.content}`,

      // Metemos los filtros en la carpeta metadata
      metadata: {
        restaurante_telefono: original.telefono,
        disponible: true
      }
    }
  };
});

const cliente = $json.cliente_nombre || "Amigo(a)";
const telefono = $json.cliente_telefono;
const idOrden = $json.orden_id;
const total = $json.total;

// Construimos el mensaje persuasivo y empático
const mensaje = `¡Hola ${cliente}! 🌿 Noté que estabas armando un pedido delicioso hace un ratito pero lo dejaste a medias (S/. ${total}). \n\n¿Tuviste algún inconveniente técnico o te quedó alguna duda con los ingredientes? 🤔 \n\nRecuerda que preparamos todo fresco y el stock de algunos platillos vuela rápido 🏃‍♂️💨. Si quieres terminar tu pedido, puedes hacerlo ingresando a la Webapp.\n\n¡Avísame si necesitas ayuda!`;

return {
  json: {
    numero_destino: telefono,
    mensaje: mensaje
  }
};
